INSERT INTO `artists` (`artist_id`, `artist_name`, `artist_image`, `genre`, `rating`, `about`, `created_at`, `updated_at`) VALUES
(1, 'BTS Concerts', '1782721571_bts.jpg', 'Pop', '4.8', 'BTS, an acronym of Bangtan Sonyeondan or âBeyond the Scene,â are a GRAMMY-nominated South Korean boyband that has been capturing the hearts of millions of fans globally since their debut in June 2013. The members of BTS are RM, Jin, SUGA, j-hope, Jimin, V, and Jung Kook. Gaining recognition for their authentic and self-produced music, top-notch performances, and the way they interact with their fans, the band has established themselves as 21st century pop icons breaking countless world records. While imparting a positive influence through activities such as the LOVE MYSELF campaign and the UN âSpeak Yourselfâ speech, the band has mobilized millions of fans across the world (named ARMY), collected six No.1 Billboard Hot 100 singles since 2020, and performed multiple sold-out stadium shows across the world. They were also named TIMEâs Entertainer of the Year 2020. BTS are 5-time GRAMMY nominees (63rd to 65th GRAMMY Awards) and have been recognized with numerous prestigious awards like the Billboard Music Awards, American Music Awards (Artist of the Year 2021) and MTV Video Music Awards. The band released their fifth studio album ARIRANG on March 20, 2026 with a massive world tour to follow, signaling a return set to be etched in pop culture history.', '2026-06-29 08:26:11', '2026-07-05 08:36:28'),
(10, 'Bad Bunny Concerts', '1782761657_Bad-Bunny.png', 'Hip-Hop/Rap', '4.7', 'Bad Bunny is a three-time Grammy and nine-time Latin Grammy Award winning performer. His versatility as a genre-defying artist has catapulted him from Latin trap beginnings to global superstar. Since topping the Billboard Hot 100 with Cardi B and J Balvin on 2018âs âI Like It,â the Puerto Rican megastar has shattered all kinds of records. In 2020, his third album El Ãltimo Tour del Mundo became the first-ever Spanish-language album to top the Billboard 200. That same year, he became Spotifyâs most-streamed artist â the first Latin artist at the time to bear the distinction â repeating the feat in 2021 and 2022. Bad Bunnyâs crossover success has made him one of the worldâs most in-demand live acts, and El Ãltimo Tour del Mundo 2022 became the highest-grossing tour by a Latin artist in Billboard Boxscore history. He shattered his own record on 2022âs Worldâs Hottest Tour, which grossed $435 million worldwide and became the highest-grossing Latin tour in Billboard history.', '2026-06-29 19:34:17', '2026-07-01 17:38:34'),
(9, 'Stray Kids Concerts', '1782761492_straykids.png', 'Pop', '4.9', 'Stray Kids are a South Korean boy band formed by JYP Entertainment in 2017. Composed of Bang Chan, Lee Know, Changbin, Hyunjin, Han, Felix, Seungmin and I.N, the group have sold over 10 million albums across five studio albums and several EPs. In 2020, Stray Kids released their debut full-length, Go Live, followed by Noeasy in 2021 and The Sound in 2023. After signing to Republic Records in the U.S., Stray Kids notched five consecutive No. 1 debuts on the Billboard 200: 2022âs Oddinary EP and Maxident EP, 2023âs 5-Star and Rock-Star EP and 2024âs Ate EP. Stray Kids have topped the Billboard World Digital Song Sales chart five times and reached the Hot 100 for the singles âLalalala,â âLose My Breathâ and âChk Chk Boom.â Over their career, the group have collaborated with Charlie Puth, Alesso, Lil Durk, Tom Morello and more. In 2024, Stray Kids followed the Ate EP with their second Japanese-language album, Giant, as well as the Hop mixtape.', '2026-06-29 19:31:32', '2026-07-01 17:38:56'),
(11, 'My Chemical Romance', '1782761768_My-Chemical-Romance.jpg', 'Rock', '4.7', 'My Chemical Romance are a rock band composed of lead vocalist Gerard Way, bassist Mikey Way and guitarists Ray Toro and Frank Iero. Formed in 2001 in New Jersey, MCR have become highly influential for their blend of rock, pop-punk and emo music along with unflinchingly open lyrics and theatrical live performances. Beginning with 2002âs I Brought You My Bullets, You Brought Me Your Love, MCR have released four studio albums, two live recordings and three compilations. The band unveiled their major label debut, Three Cheers for Sweet Revenge, in 2004 behind their first charting singles, âI\'m Not Okay (I Promise),â âHelenaâ and âThe Ghost of You.â In 2006, MCRâs third album The Black Parade reached a career-high No. 2 on the Billboard 200, while lead single âWelcome to the Black Paradeâ peaked at No. 9 on the Hot 100. After touring 2010âs Danger Days: The True Lives of the Fabulous Killjoys, MCR did not perform together again until 2019, followed by a reunion world tour between 2022 and 2023. The band headlined Las Vegasâ When We Were Young Festival in 2024. In 2025, My Chemical Romance embarked on a tour in celebration of the 20th anniversary of their landmark third studio album, The Black Parade.', '2026-06-29 19:36:07', '2026-06-29 19:36:07'),
(12, 'Olivia Rodrigo', '1782761849_Olivia.jpg', 'Pop', '4.8', 'Olivia Rodrigo is a generation-defining artist known for her heartfelt blend of confessional pop lyricism and rock-leaning sound. After rising to prominence with Disneyâs High School Musical: The Musical: The Series, Olivia Rodrigo released her breakout single âdriverâs license,â which marked her first Billboard No. 1 on the Hot 100 and remained in the top slot for eight consecutive weeks. Olivia Rodrigo released her debut album, SOUR, in 2021, yielding singles like âdeja vuâ and âgood 4 uâ and earning her the Grammy Award for Best New Artist. Her sophomore album, GUTS, arrived in 2023 and debuted at No. 1 on the Billboard 200 albums chart. Supported by the GUTS World Tour, the album won the Grammy for Best Pop Vocal Album and received an Album of the Year nod at the 2024 Grammy Awards. With a deep well of artistic inspirations, Olivia Rodrigo has collaborated with musical legends like Billy Joel, David Byrne, and Robert Smith, and earned recognition from figures like Alanis Morissette, who said, âWe\'re all going to be okay if Olivia Rodrigo exists.â Olivia Rodrigoâs third studio album, you seem pretty sad for a girl so in love, is set to be released on June 12, 2026. âdrop dead,â the first song released from you seem pretty sad for a girl so in love, debuted at No. 1 on the Billboard Hot 100 chart, making Rodrigo the first artist to debut the lead singles from all of her studio albums in that position. Rodrigo is also the only artist born this century with multiple Hot 100 No. 1s (âdrop dead,â âvampire,â âgood 4 u,â âdrivers licenseâ). In 2026, Olivia Rodrigo will embark on The Unraveled Tour.', '2026-06-29 19:37:29', '2026-06-29 19:37:29'),
(13, 'Benson Boone', '1782761929_Benson-Boone.jpg', 'Rock', '4.9', 'Benson Boone is a singer, songwriter and multi-instrumentalist from Monroe, Washington. The rising pop sensation first gained a following by sharing videos on TikTok and eventually caught the attention of Imagine Dragons lead singer Dan Reynolds, who signed him to his Night Street Records in partnership with Warner Records in 2021. Early entries on the Billboard Hot 100 included âGHOST TOWNâ and âIn the Stars,â both of which appeared on his debut EP, Walk Me Homeâ¦, in 2022. The singerâs sophomore EP, PULSE, arrived in 2023 and coincided with his first worldwide headlining tour. Ahead of Booneâs 2024 debut album Fireworks & Rollerblades, lead single âBeautiful Thingsâ became the biggest hit of his career thus far, debuting at No. 15 on the Hot 100 and later reaching a peak of No. 2 on the chart. In 2025, Boone earned a Grammy nomination for Best New Artist. Preceded by singles âSorry Iâm Here for Someone Elseâ and âMystical Magical,â his sophomore album, American Heart, was released on June 20, 2025.', '2026-06-29 19:38:49', '2026-06-29 19:38:49'),
(14, 'Gracie Abrams', '1782761995_Gracie-Abrams.jpg', 'Pop', '4.9', 'Gracie Abrams is a singer-songwriter from Los Angeles, California. Abrams signed to Interscope Records in 2019 and released a pair of EPs titled Minor and This Is What It Feels Like over the following two years. Abramsâ debut full-length, Good Riddance, was released in 2023 â the same year she collaborated with Noah Kahan on âEverything, Everywhereâ and served as an opener for Taylor Swift on The Eras Tour. Preceded by the lead single âRisk,â the singerâs sophomore album, The Secret of Us, was released to critical acclaim on June 21, 2024. The Secret of Us was co-produced by Abrams and her longtime collaborator, Aaron Dessner of The National, and marked the first time Abrams took a role in the production process of her music. Abramsâ third studio album, Daughter From Hell, is set to be released on July 17, 2026, and features the lead single âHit the Wall.â', '2026-06-29 19:39:54', '2026-06-29 19:39:54'),
(15, 'The Weeknd', '1782762076_Weeknd.jpg', 'Hip-Hop/Rap', '4.7', 'The Weeknd is a Grammy-winning R&B/pop artist from Toronto, Ontario. He first gained recognition in 2009 after releasing music anonymously and sparked international acclaim with his 2011 breakthrough mixtapes House of Balloons, Thursday and Echoes of Silence. The Weekndâs albums Beauty Behind the Madness (2015) and Starboy (2016) established him as a pop phenomenon, earning multiple Grammy Awards and producing chart-topping hits like \"Can\'t Feel My Face.\" His 2020 album After Hours became his fourth set to reach No. 1 on the Billboard 200. In 2021, he performed at the Super Bowl LV halftime show, further cementing his status as a global pop superstar. His sixth studio album, Hurry Up Tomorrow, was released on January 31, 2025. For nearly a decade, The Weeknd has consistently sold out stadiums worldwide, and is set to continue his record-smashing After Hours Til Dawn Tour through 2025. Outside of music, The Weeknd has donated millions of dollars to humanitarian causes, including establishing the XO Humanitarian Fund in 2022 in partnership with the United Nations World Food Programme. In 2021 he was named a Goodwill Ambassador for the WFP and has also donated to other causes including COVID-19 relief, Black Lives Matter and Los Angeles wildfire relief.', '2026-06-29 19:41:16', '2026-06-29 19:41:16'),
(16, 'Post Malone', '1782762147_PostMalone.jpg', 'Hip-Hop/Rap', '4.7', 'Post Malone is a Texas-raised singer, songwriter, rapper and one of the best-selling artists of the 21st century. The self-taught musician, born Austin Post, has earned two No. 1 albums on the Billboard 200 and six No. 1 singles on the Hot 100. He has also received 10 Grammy nominations, holds a record nine RIAA-certified diamond singles and ties only The Weeknd as a lead artist with five of Spotifyâs Top 100 most-streamed songs. Following his breakthrough 2015 single âWhite Iverson,â Post Malone released his full-length debut, Stoney, in 2016. His 2018 sophomore album Beerbongs & Bentleys topped the Billboard 200, led by his first two No. 1 singles âRockstarâ and âPsycho.â Later that year, his Swae Lee collaboration âSunflowerâ peaked at No. 1 on the Hot 100 and went on to become the RIAAâs first-ever double-diamond record. His third album Hollywoodâs Bleeding in 2019 earned Post Malone his second No. 1 debut behind the Hot 100-topping single âCircles,â which capped 200 consecutive weeks on the chart for the artist. Post Maloneâs fourth full-length Twelve Carat Toothache arrived in 2022, quickly followed by 2023âs Austin. In 2024, Post Malone released his sixth solo effort, F-1 Trillion. The following year, he began his Big Ass Stadium Tour. In 2026, Post Malone will embark on the Big Ass Stadium Tour Part 2.', '2026-06-29 19:42:27', '2026-06-29 19:42:27'),
(17, 'Chappell Roan', '1782762227_ChappellRoan.jpg', 'Pop', '4.9', 'Bold pop hooks, honest songwriting, and a heavy dose of glitter make up the world of Chappell Roan, the next multi-faceted force in pop music. Through her punchy bangers that combine fantastical narratives and heart-baring self-reflection, the LA-based singer, songwriter, and performer has emerged as the rare star who is both larger than life and real as hell. Throughout a momentous 2022, with two sold-out national tours in one year, and critical acclaim from Rolling Stone, the LA Times, Pitchfork, V Mag, Line of Best Fit, Nylon, NPR, Clash, Vulture, Billboard, OUT, among many others, her debut album, The Rise and Fall of a Midwest Princess, was released on September 22, 2023 via Amusement Records/Island Records.', '2026-06-29 19:43:47', '2026-06-29 19:43:47'),
(18, 'Drake', '1782762350_Drake.jpg', 'Hip-Hop/Rap', '4.7', 'Drake is hip-hopâs preeminent superstar. In less than a decade, the Canadian rapper has won five Grammy Awards, landed 11 No. 1 hits on the Billboard Hot 100, and in 2022 became the highest-selling singles artist in the history of the RIAA. Drakeâs first three albums â Thank Me Later (2010), Take Care (2011) and Nothing Was the Same (2013) â were all critical successes, showcasing a pioneering sound that mixed catchy R&B hooks with heartfelt lyricism. His fourth album, Views (2016), held atop the Billboard 200 for 13 nonconsecutive weeks, smashing more records â including Drake becoming the most-streamed artist in Spotify history. That same year, he embarked on a co-headlining tour with Future that became the highest-grossing hip-hop tour of all time, grossing over $84 million across 56 dates.', '2026-06-29 19:45:50', '2026-06-29 19:45:50'),
(20, 'Family. Children\'s Art, Theater & comedy.', '1782924591_ChatGPT Image Jul 1, 2026, 05_47_47 PM.png', 'Children\'s Theater', '4.9', 'About Family & Childrenâs Entertainment\r\nFamily and childrenâs events bring joy, creativity, and laughter to audiences of all ages. From colorful art showcases and imaginative theater productions to lighthearted comedy designed for young minds, these experiences spark curiosity and strengthen bonds. Childrenâs theater introduces little ones to the magic of storytelling, while family-friendly comedy ensures everyone leaves with a smile. Together, these events create lasting memories, nurture imagination, and celebrate the power of shared entertainment.', '2026-07-01 16:49:52', '2026-07-01 16:49:52'),
(21, 'Art Theater & comedy.', '1782926449_ChatGPT Image Jul 1, 2026, 06_16_46 PM.png', 'Art Theater & Comedy, Broadway, Spectacular', '4.9', 'About Art, Theater & Comedy\r\nArt, theater, and comedy are timeless forms of expression that bring people together through creativity and laughter. Theater showcases the power of storytelling, transporting audiences into worlds of imagination and emotion. Comedy adds lightness and joy, reminding us of the humor in everyday life. Art in all its formsâvisual, performance, and spokenâsparks inspiration and challenges us to see the world differently. Together, these experiences celebrate culture, creativity, and the shared human spirit.', '2026-07-01 17:20:50', '2026-07-01 17:23:23'),
(22, 'SPORTS NBA Tickets', '1782927308_ChatGPT Image Jul 1, 2026, 06_32_41 PM.png', 'NBA Tickets', '4.7', 'About Sports & NBA Tickets\r\nSports ignite passion, unity, and unforgettable moments. Among them, the NBA stands as one of the most electrifying leagues in the world, showcasing athleticism, skill, and drama on the court. NBA tickets give fans the chance to witness slam dunks, buzzer-beaters, and legendary rivalries live, creating experiences that go beyond the game. Whether itâs cheering for your hometown team or watching global superstars in action, NBA events embody the thrill of competition and the joy of shared fandom.', '2026-07-01 17:35:08', '2026-07-01 17:35:08'),
(23, 'Harry Styles', '1783379865_aXJWMQIvOtkhB08y_EADP-Desktop-Header-ED.avif', 'Pop', '4.9', 'British singer, songwriter, and actor Harry Styles is on a mission to treat people with kindness â and heâs become a culture-shifting pop star along the way. Following his origins as a member of record-breaking The X-Factor UK band One Direction, Harry Styles established himself as a soloist, blending pop, rock, and soul with a nostalgic visual language and an energetic brand of showmanship. Styles has released three studio albums that yielded accolades from a number of prominent institutions, including the MTV VMAs, AMAs, Brit Awards, and Grammys â his three wins from the Recording Academy include the prestigious Album of the Year, which he won for 2022âs Harryâs House. Styles has undertaken multiple headlining tours and established himself as a major force in live performance; his massively successful Love On Tour, which took place from September 2021 to July 2023, ended its run as the fifth-highest grossing and eighth-most attended tour in history. During that time, he broke records at Madison Square Garden with a 15-night residency that became the highest-grossing single engagement in the venueâs history. Stylesâ fourth studio album, titled Kiss All the Time. Disco, Occasionally., is set to be released on March 6, 2026.', '2026-07-06 23:17:44', '2026-07-06 23:17:44'),
(24, 'Noah Kahan Tickets', '1783391095_aXqWsAIvOtkhCDQ9_EADP-Desktop-Header-NOahKahan.jpg', 'Rock', '4.9', 'Two-time GRAMMY-nominated, multi-platinum Vermont singer-songwriter Noah Kahan has risen from his New England roots to become a globally resonant voice of his generation. Across his career, Kahan has amassed nearly 15 billion global streams, sold nearly 12 million global albums, and earned 22 Platinum and Gold certifications. In addition to receiving two GRAMMY nominations, heâs been recognized by the BRIT Awards, Billboard Music Awards, iHeart Radio Music Awards, Peopleâs Choice Awards, Americana Honors & Awards, and more.\r\n\r\nKahanâs critically acclaimed breakthrough 2022 album Stick Season became a cultural phenomenon. Over the span of two years, the 4x Platinum album and its 8x Platinum title track reached number one across North America, the UK, and Europe, becoming the fourth best-selling album of 2024 and remaining in the Top 15 more than three years after its release. In 2023 following the release of Stick Season, Kahan launched his mental health non-profit, The Busyhead Project, which has raised over $5.5 million to date in support of its mission to increase awareness around the importance of mental health.\r\n\r\nNow, Kahan enters his next artistic era with The Great Divide, his fourth studio album, due April 24th via Mercury Records. Written in the wake of his rapid rise to global fame, the album finds Kahan at his most honest, reflective, and emotionally resonantâgrappling with success, identity, family, distance, and the unspoken truths that separate people from one another. Produced by acclaimed producer and Stick Season collaborator Gabe Simon (Dua Lipa, Lana Del Rey, Koe Wetzel) alongside GRAMMY-winning producer Aaron Dessner (Taylor Swift, Bon Iver), The Great Divide builds on Kahanâs signature storytelling while pushing his sound into more expansive, anthemic, and sonically adventurous territory. In support of the new album, Kahan will embark on The Great Divide Tour this summer, headlining stadiums across North America for his biggest tour to date. At the heart of Noah Kahanâs music remains the same guiding purpose that first drew fans in: honest storytelling, shared vulnerability, and songs that help listeners feel understood.', '2026-07-07 02:24:54', '2026-07-07 02:24:54');
