INSERT INTO `faqs` (`faq_id`, `artist_id`, `question`, `answer`, `created_at`) VALUES
(1, 1, 'When is BTS going on tour?', 'BTS will kick off the North American leg of their 2026 world tour on April 25, 2026 with a show at Raymond James Stadium in Tampa, Florida. The North American run will wrap in September 2026 with four shows at Los Angelesâ SoFi Stadium.', '2026-06-29 11:02:53'),
(2, 1, 'When does the BTS tour start?', 'The BTS WORLD TOUR IN NORTH AMERICA & EUROPE begins on April 25 in Tampa, Florida at Raymond James Stadium.', '2026-06-29 11:03:31'),
(3, 18, 'When does the BTS tour start?', 'fghj', '2026-07-01 07:40:53');
