INSERT INTO `reviews` (`review_id`, `artist_id`, `rating`, `title`, `uploaded_by`, `review_date`, `description`, `created_at`) VALUES
(1, 1, '5.0', 'A wonderful experience', 'ChristinaRN', '2026-06-26', 'I saw the ARIRANG live movie concert first and enjoyed it a lot, so I thought I knew what I could expect from the concert. I was wrong. It was so, so much better live. The energy from BTS and the stage design from this ARIRANG tour are things one needs to experience in person. If you find a ticket, I would recommend you donât miss this opportunity. Even if youâre not a hardcore fan, I guarantee youâll have a wonderful experience.', '2026-06-29 11:10:32'),
(2, 1, '5.0', '360 stage', 'Lala', '2026-06-25', 'I\'m not Army, I took my sister who has been waiting for BTS to come for years. Day1 & 2 in Tampa. The show was amazing. I\'m loving the new album & the songs they sung at the concert. Definitely will see them again.', '2026-06-29 11:11:22');
INSERT INTO `setlists` (`setlist_id`, `artist_id`, `title`, `location`, `event_date`, `description`, `created_at`) VALUES
(1, 1, 'ARIRANG at Riyadh Air Metropolitano', 'Madrid, Spain', '2026-06-27', 'Act I\r\n1.\r\nHooligan\r\n2.\r\nAliens\r\n3.\r\nRun BTS (remix)\r\n-\r\nMent\r\n4.\r\nthey don\'t know \'bout us\r\n5.\r\nLike Animals (With transition into FAKE LOVE)\r\n6.\r\nFAKE LOVE (remix)\r\n7.\r\nSWIM\r\n8.\r\nMerry Go Round (extended outro)\r\nAct II\r\n9.\r\n2.0\r\n10.\r\nNORMAL\r\n-\r\nMent\r\n11.\r\nNot Today (remix)\r\n12.\r\nMIC Drop\r\n13.\r\nFYA\r\n14.\r\nFire (with elements of FYA)\r\n15.\r\nBody to Body\r\n16.\r\nIDOL (extended outro)\r\nEncore\r\n17.\r\nCome Over\r\n18.\r\nButter\r\n19.\r\nDynamite\r\n20.\r\nMikrokosmos\r\n21.\r\nBest of Me\r\n-\r\nMent\r\n22.\r\nPlease\r\n23.\r\nInto the Sun (extended outro)', '2026-06-29 10:30:51');
